다음 C 프로그램의 실행 결과로 옳은 것은? (동적할당과 포인터 순회)

```c
#include <stdio.h>
#include <stdlib.h>
int main() {
    int *p = (int *)malloc(sizeof(int) * 3);
    int i, sum = 0;
    for (i = 0; i < 3; i++)
        *(p + i) = (i + 1) * 10;
    for (i = 0; i < 3; i++)
        sum += p[i];
    printf("%d", sum);
    free(p);
    return 0;
}
```

